1	import { z } from "zod";
2	import { PROVIDER_DISPLAY } from "../../client/display";
3	import { defineWebhookProvider } from "../../factory/index";
4	import { actionEvent, hmac } from "../../provider/index";
5	import type { CallbackResult } from "../../provider/primitives";
6	import { readErrorBody } from "../../runtime/http";
7	import { createRS256JWT } from "../../runtime/jwt";
8	import {
9	  githubApi,
10	  githubAppInstallationSchema,
11	  githubInstallationReposSchema,
12	} from "./api";
13	import type { GitHubAccountInfo, GitHubConfig } from "./auth";
14	import {
15	  githubAccountInfoSchema,
16	  githubConfigSchema,
17	  githubProviderConfigSchema,
18	} from "./auth";
19	import { githubBackfill } from "./backfill";
20	import {
21	  githubWebhookPayloadSchema,
22	  preTransformGitHubIssuesEventSchema,
23	  preTransformGitHubPullRequestEventSchema,
24	} from "./schemas";
25	import {
26	  transformGitHubIssue,
27	  transformGitHubPullRequest,
28	} from "./transformers";
29	
30	// ── GitHub-Specific Capabilities ──
31	
32	async function createGitHubAppJWT(config: GitHubConfig): Promise<string> {
33	  const now = Math.floor(Date.now() / 1000);
34	  return createRS256JWT(
35	    { iss: config.appId, iat: now - 60, exp: now + 600 },
36	    config.privateKey
37	  );
38	}
39	
40	async function getInstallationToken(
41	  config: GitHubConfig,
42	  installationId: string
43	): Promise<string> {
44	  if (!/^\d+$/.test(installationId)) {
45	    throw new Error("Invalid GitHub installation ID: must be numeric");
46	  }
47	
48	  const jwt = await createGitHubAppJWT(config);
49	  const response = await fetch(
50	    `https://api.github.com/app/installations/${installationId}/access_tokens`,
51	    {
52	      method: "POST",
53	      signal: AbortSignal.timeout(10_000),
54	      headers: {
55	        Authorization: `Bearer ${jwt}`,
56	        Accept: "application/vnd.github+json",
57	        "User-Agent": "lightfast-platform",
58	        "X-GitHub-Api-Version": "2022-11-28",
59	      },
60	    }
61	  );
62	  if (!response.ok) {
63	    const body = await readErrorBody(response);
64	    throw new Error(
65	      `GitHub installation token request failed: ${response.status} ${body}`
66	    );
67	  }
68	
69	  const data = (await response.json()) as Record<string, unknown>;
70	  if (typeof data.token !== "string" || data.token.length === 0) {
71	    throw new Error("GitHub installation token response missing valid token");
72	  }
73	  return data.token;
74	}
75	
76	// ── Provider Definition ──
77	
78	export const github = defineWebhookProvider({
79	  ...PROVIDER_DISPLAY.github,
80	  configSchema: githubConfigSchema,
81	  accountInfoSchema: githubAccountInfoSchema,
82	  providerConfigSchema: githubProviderConfigSchema,
83	
84	  categories: {
85	    pull_request: {
86	      label: "Pull Requests",
87	      description: "Capture PR opens, merges, closes, and reopens",
88	      type: "observation",
89	    },
90	    issues: {
91	      label: "Issues",
92	      description: "Capture issue opens, closes, and reopens",
93	      type: "observation",
94	    },
95	  },
96	
97	  events: {
98	    pull_request: actionEvent({
99	      label: "Pull Requests",
100	      weight: 50,
101	      schema: preTransformGitHubPullRequestEventSchema,
102	      transform: transformGitHubPullRequest,
103	      actions: {
104	        opened: { label: "PR Opened", weight: 50 },
105	        closed: { label: "PR Closed", weight: 45 },
106	        merged: { label: "PR Merged", weight: 60 },
107	        reopened: { label: "PR Reopened", weight: 40 },
108	        "ready-for-review": { label: "Ready for Review", weight: 45 },
109	      },
110	    }),
111	    issues: actionEvent({
112	      label: "Issues",
113	      weight: 45,
114	      schema: preTransformGitHubIssuesEventSchema,
115	      transform: transformGitHubIssue,
116	      actions: {
117	        opened: { label: "Issue Opened", weight: 45 },
118	        closed: { label: "Issue Closed", weight: 40 },
119	        reopened: { label: "Issue Reopened", weight: 40 },
120	      },
121	    }),
122	  },
123	
124	  webhook: {
125	    headersSchema: z.object({
126	      "x-hub-signature-256": z.string(),
127	      "x-github-event": z.string(),
128	      "x-github-delivery": z.string(),
129	    }),
130	    extractSecret: (config) => config.webhookSecret,
131	    signatureScheme: hmac({
132	      algorithm: "sha256",
133	      signatureHeader: "x-hub-signature-256",
134	      prefix: "sha256=",
135	    }),
136	    extractEventType: (headers) => headers.get("x-github-event") ?? "unknown",
137	    extractDeliveryId: (headers) =>
138	      headers.get("x-github-delivery") ?? crypto.randomUUID(),
139	    extractResourceId: (payload) => {
140	      const p = payload as {
141	        repository?: { id: number | string };
142	        installation?: { id: number | string };
143	      };
144	      if (p.repository?.id != null) {
145	        return String(p.repository.id);
146	      }
147	      if (p.installation?.id != null) {
148	        return String(p.installation.id);
149	      }
150	      return null;
151	    },
152	    parsePayload: (raw) => githubWebhookPayloadSchema.parse(raw),
153	  },
154	
155	  auth: {
156	    kind: "app-token" as const,
157	    buildInstallUrl: (config, state) => {
158	      const url = new URL(
159	        `https://github.com/apps/${config.appSlug}/installations/new`
160	      );
161	      url.searchParams.set("state", state);
162	      return url.toString();
163	    },
164	    usesStoredToken: false as const,
165	    getActiveToken: async (config, storedExternalId, _storedAccessToken) => {
166	      return getInstallationToken(config, storedExternalId);
167	    },
168	    getAppToken: async (config) => createGitHubAppJWT(config),
169	    revokeAccess: async (config, _externalId) => {
170	      // GitHub App installations are revoked via the GitHub UI or GitHub API.
171	      // Installation tokens expire automatically; no explicit revocation call needed.
172	      // The app can be uninstalled via DELETE /app/installations/:installation_id.
173	      const jwt = await createGitHubAppJWT(config);
174	      const response = await fetch(
175	        `https://api.github.com/app/installations/${_externalId}`,
176	        {
177	          method: "DELETE",
178	          signal: AbortSignal.timeout(15_000),
179	          headers: {
180	            Authorization: `Bearer ${jwt}`,
181	            Accept: "application/vnd.github+json",
182	            "User-Agent": "lightfast-platform",
183	            "X-GitHub-Api-Version": "2022-11-28",
184	          },
185	        }
186	      );
187	      // 204 = success, 404 = already uninstalled — both are fine
188	      if (!response.ok && response.status !== 404) {
189	        const body = await readErrorBody(response);
190	        throw new Error(
191	          `GitHub installation revocation failed: ${response.status} ${body}`
192	        );
193	      }
194	    },
195	    processCallback: (_config, query) => {
196	      const installationId = query.installation_id;
197	      const setupAction = query.setup_action;
198	
199	      if (setupAction === "request") {
200	        return Promise.reject(
201	          new Error("setup_action=request is not yet implemented")
202	        );
203	      }
204	      if (setupAction === "update") {
205	        return Promise.reject(
206	          new Error("setup_action=update is not yet implemented")
207	        );
208	      }
209	      if (!installationId) {
210	        return Promise.reject(new Error("missing installation_id"));
211	      }
212	
213	      const now = new Date().toISOString();
214	      return Promise.resolve({
215	        status: "connected-no-token",
216	        externalId: installationId,
217	        accountInfo: {
218	          version: 1 as const,
219	          sourceType: "github" as const,
220	          events: ["pull_request", "issues"],
221	          installedAt: now,
222	          lastValidatedAt: now,
223	          raw: {},
224	        },
225	      } satisfies CallbackResult<GitHubAccountInfo>);
226	    },
227	  },
228	
229	  defaultSyncEvents: ["pull_request", "issues"],
230	
231	  buildProviderConfig: ({ defaultSyncEvents }) => ({
232	    provider: "github" as const,
233	    type: "repository" as const,
234	    sync: {
235	      events: [...defaultSyncEvents],
236	      autoSync: true,
237	    },
238	  }),
239	
240	  // GitHub wire eventType maps 1:1 to event key (e.g., "push" → "push")
241	  resolveCategory: (eventType) => eventType,
242	
