1	/**
2	 * Event store workflow (fast path)
3	 *
4	 * Stores facts from PostTransformEvents: event row + entities + junction rows.
5	 * No LLM calls, no embeddings — completes in <2s.
6	 *
7	 * Workflow steps:
8	 * 1. Check for duplicate events (idempotency)
9	 * 2. Check if event is allowed by source config (filtering)
10	 * 3. Evaluate significance (stored as metadata, not a gate)
11	 * 4. Extract entities (structural categories from relations)
12	 * 5. Store event row
13	 * 6. Upsert entities + create junction rows
14	 * 7. Emit entity.upserted (triggers entity-graph -> entity-embed chain)
15	 * 8. Complete job
16	 */
17	
18	import { db } from "@db/app/client";
19	import {
20	  orgEntities,
21	  orgEventEntities,
22	  orgEvents,
23	  orgIntegrations,
24	} from "@db/app/schema";
25	import type { ProviderConfig } from "@repo/app-providers";
26	import { deriveObservationType, getBaseEventType } from "@repo/app-providers";
27	import type {
28	  EntityCategory,
29	  EventCaptureInput,
30	  EventCaptureOutputFailure,
31	  EventCaptureOutputFiltered,
32	  EventCaptureOutputSuccess,
33	  ExtractedEntity,
34	} from "@repo/app-validation";
35	import { NonRetriableError } from "@vendor/inngest";
36	import { log } from "@vendor/observability/log/next";
37	import { and, eq, sql } from "drizzle-orm";
38	import { nanoid } from "nanoid";
39	import {
40	  extractEntities,
41	  extractFromRelations,
42	} from "../../lib/entity-extraction-patterns";
43	import { completeJob, createJob, updateJobStatus } from "../../lib/jobs";
44	import { scoreSignificance } from "../../lib/scoring";
45	import { inngest } from "../client";
46	import { createNeuralOnFailureHandler } from "../on-failure-handler";
47	
48	const STRUCTURAL_TYPES = new Set([
49	  "commit",
50	  "branch",
51	  "pr",
52	  "issue",
53	  "deployment",
54	]);
55	
56	/**
57	 * Check if an event type is allowed for a source based on providerConfig.sync.events
58	 */
59	function isEventAllowed(
60	  providerConfig: ProviderConfig | null | undefined,
61	  baseEventType: string
62	): boolean {
63	  const events = providerConfig?.sync?.events;
64	  if (!events || events.length === 0) {
65	    return true;
66	  }
67	  return events.includes(baseEventType);
68	}
69	
70	/**
71	 * Event store workflow
72	 *
73	 * Fast path: stores facts only. No LLM, no embeddings.
74	 * Emits entity.upserted to trigger the entity-graph -> entity-embed chain.
75	 */
76	export const platformEventStore = inngest.createFunction(
77	  {
78	    id: "platform/event.store",
79	    name: "Event Store",
80	    description: "Stores engineering events (fast path)",
81	    retries: 3,
82	
83	    // Idempotency by org + source ID to prevent duplicate observations per org
84	    idempotency:
85	      "event.data.clerkOrgId + '-' + event.data.sourceEvent.sourceId",
86	
87	    // Concurrency limit per org
88	    concurrency: {
89	      limit: 10,
90	      key: "event.data.clerkOrgId",
91	    },
92	
93	    timeouts: {
94	      start: "1m",
95	      finish: "2m",
96	    },
97	
98	    // Handle failures gracefully - complete job as failed
99	    onFailure: createNeuralOnFailureHandler("platform/event.capture", {
100	      logMessage: "Neural observation store failed",
101	      logContext: ({ clerkOrgId, sourceEvent }) => ({
102	        clerkOrgId,
103	        sourceId: sourceEvent.sourceId,
104	      }),
105	      buildOutput: ({ data: { sourceEvent }, error }) =>
106	        ({
107	          inngestFunctionId: "event.capture",
108	          status: "failure",
109	          sourceId: sourceEvent.sourceId,
110	          error,
111	        }) satisfies EventCaptureOutputFailure,
112	    }),
113	  },
114	  { event: "platform/event.capture" },
115	  async ({ event, step }) => {
116	    const { clerkOrgId, sourceEvent, ingestLogId, correlationId } = event.data;
117	
118	    // Generate replay-safe values inside steps so they're memoized across retries.
119	    const { externalId, startTime } = await step.run(
120	      "generate-replay-safe-ids",
121	      () => ({
122	        externalId: nanoid(),
123	        startTime: Date.now(),
124	      })
125	    );
126	
127	    // Step 0: Create job record for tracking
128	    const inngestRunId =
129	      event.id ?? `neural-obs-${sourceEvent.sourceId}-${startTime}`;
130	    const jobId = await step.run("create-job", async () => {
131	      return createJob({
132	        clerkOrgId,
133	        inngestRunId,
134	        inngestFunctionId: "platform/event.capture",
135	        name: `Capture ${sourceEvent.provider}/${sourceEvent.eventType}`,
136	        trigger: "webhook",
137	        input: {
138	          inngestFunctionId: "event.capture",
139	          sourceId: sourceEvent.sourceId,
140	          source: sourceEvent.provider,
141	          sourceType: sourceEvent.eventType,
142	          title: sourceEvent.title,
143	        } satisfies EventCaptureInput,
144	      });
145	    });
146	
147	    await step.run("update-job-running", async () => {
148	      await updateJobStatus(jobId, "running");
149	    });
150	
151	    // Step 1: Check for duplicate
152	    const existing = await step.run("check-duplicate", async () => {
153	      const obs = await db.query.orgEvents.findFirst({
154	        where: and(
155	          eq(orgEvents.clerkOrgId, clerkOrgId),
156	          eq(orgEvents.sourceId, sourceEvent.sourceId)
157	        ),
158	      });
159	
160	      if (obs) {
161	        log.info("observation already exists, skipping", {
162	          observationId: obs.id,
163	          sourceId: sourceEvent.sourceId,
164	        });
165	      }
166	
167	      return obs ?? null;
168	    });
169	
170	    if (existing) {
171	      await step.run("complete-job-duplicate", async () => {
172	        await completeJob({
173	          jobId,
174	          status: "completed",
175	          output: {
176	            inngestFunctionId: "event.capture",
177	            status: "filtered",
178	            reason: "duplicate",
179	            sourceId: sourceEvent.sourceId,
180	          } satisfies EventCaptureOutputFiltered,
181	        });
182	      });
183	
184	      return {
185	        status: "duplicate",
186	        observationId: existing.id,
187	        duration: Date.now() - startTime,
188	      };
189	    }
190	
191	    // Step 2: Check if event is allowed by source config
192	    const gateResult = await step.run("check-event-allowed", async () => {
193	      const attributes = sourceEvent.attributes;
194	
195	      let resourceId: string | undefined;
196	      switch (sourceEvent.provider) {
197	        case "github":
198	          resourceId =
199	            attributes.repoId != null ? String(attributes.repoId) : undefined;
200	          break;
201	        case "vercel":
202	          resourceId =
203	            attributes.projectId != null
204	              ? String(attributes.projectId)
205	              : undefined;
206	          break;
207	        case "sentry":
208	          resourceId =
209	            attributes.projectId != null
210	              ? String(attributes.projectId)
211	              : undefined;
212	          break;
213	        case "linear":
214	          resourceId =
215	            attributes.teamId != null ? String(attributes.teamId) : undefined;
216	          break;
217	        default:
218	          resourceId = undefined;
219	      }
220	
221	      if (!resourceId) {
222	        log.info("no resource ID, rejecting event", {
223	          eventType: sourceEvent.eventType,
224	        });
225	        return {
226	          allowed: false as const,
227	          reason: "event_not_allowed" as const,
228	        };
229	      }
230	
231	      const integration = await db.query.orgIntegrations.findFirst({
232	        where: and(
233	          eq(orgIntegrations.clerkOrgId, clerkOrgId),
234	          eq(orgIntegrations.providerResourceId, resourceId)
235	        ),
236	      });
237	
238	      if (!integration) {
239	        log.info("integration not found, rejecting event", {
240	          resourceId,
241	        });
242	        return {
243	          allowed: false as const,
244	          reason: "event_not_allowed" as const,
245	        };
246	      }
247	
248	      // Gate 2: check integration is active
249	      if (integration.status !== "active") {
250	        log.info("integration not active, rejecting (Gate 2)", {
251	          integrationStatus: integration.status,
252	          statusReason: integration.statusReason,
253	        });
254	        return {
255	          allowed: false as const,
256	          reason: "inactive_connection" as const,
257	        };
258	      }
259	
260	      const baseEventType = getBaseEventType(
261	        sourceEvent.provider,
262	        sourceEvent.eventType
263	      );
264	      const allowed = isEventAllowed(integration.providerConfig, baseEventType);
265	
266	      if (!allowed) {
267	        log.info("event filtered by provider config", {
268	          eventType: sourceEvent.eventType,
269	          baseEventType,
270	          configuredEvents: integration.providerConfig?.sync?.events,
271	        });
272	      }
273	
274	      return {
275	        allowed,
276	        reason: allowed ? ("allowed" as const) : ("event_not_allowed" as const),
277	      };
278	    });
279	
280	    if (!gateResult.allowed) {
281	      const filteredReason =
282	        gateResult.reason === "inactive_connection"
283	          ? ("inactive_connection" as const)
284	          : ("event_not_allowed" as const);
285	
286	      await step.run("complete-job-filtered", async () => {
287	        await completeJob({
288	          jobId,
289	          status: "completed",
290	          output: {
291	            inngestFunctionId: "event.capture",
292	            status: "filtered",
293	            reason: filteredReason,
294	            sourceId: sourceEvent.sourceId,
295	          } satisfies EventCaptureOutputFiltered,
296	        });
297	      });
298	
299	      return {
300	        status: "filtered",
301	        reason:
302	          filteredReason === "inactive_connection"
303	            ? "Integration is not active"
304	            : "Event type not enabled in source config",
305	        duration: Date.now() - startTime,
306	      };
307	    }
308	
309	    // Step 3: Evaluate significance (metadata annotation, not a gate)
310	    const significance = await step.run("evaluate-significance", () => {
311	      return scoreSignificance(sourceEvent);
312	    });
313	
314	    // Step 4: Extract entities (structural categories from relations)
315	    const extractedEntities = await step.run("extract-entities", () => {
316	      const textEntities = extractEntities(sourceEvent.title, sourceEvent.body);
317	      const refEntities = extractFromRelations(sourceEvent.relations);
318	
319	      // Primary entity from sourceEvent.entity — always upserted with highest
320	      // confidence so entity-embed can always find it by (clerkOrgId, category, key).
321	      // value is undefined so refLabel on the junction row stays null (it has no
322	      // relationship-type label — it IS the event's primary subject).
323	      const primaryEntityExtracted: ExtractedEntity = {
324	        category: sourceEvent.entity.entityType as EntityCategory,
325	        key: sourceEvent.entity.entityId,
326	        value: undefined,
327	        confidence: 1.0,
328	        evidence: `Primary entity: ${sourceEvent.entity.entityType}`,
329	        state: sourceEvent.entity.state ?? undefined,
330	        url: sourceEvent.entity.url ?? undefined,
331	      };
332	
333	      // Primary entity first — Map insertion order preserved, so it is always
334	      // at index 0 of deduplicated (used to retrieve externalId after upsert).
335	      const allEntities = [
336	        primaryEntityExtracted,
337	        ...textEntities,
338	        ...refEntities,
339	      ];
340	      const entityMap = new Map<string, ExtractedEntity>();
341	
342	      for (const entity of allEntities) {
343	        const key = `${entity.category}:${entity.key.toLowerCase()}`;
344	        const existingEntity = entityMap.get(key);
345	        if (!existingEntity || existingEntity.confidence < entity.confidence) {
346	          entityMap.set(key, entity);
347	        }
348	      }
349	
350	      const deduplicated = Array.from(entityMap.values());
351	      return deduplicated.slice(0, 50); // MAX_ENTITIES_PER_OBSERVATION
352	    });
353	
354	    // Step 5: Store observation row
355	    const observation = await step.run("store-observation", async () => {
356	      const observationType = deriveObservationType(
357	        sourceEvent.provider,
358	        sourceEvent.eventType
359	      );
360	
361	      const [obs] = await db
362	        .insert(orgEvents)
363	        .values({
364	          externalId,
365	          clerkOrgId,
366	          occurredAt: sourceEvent.occurredAt,
367	          observationType,
368	          title: sourceEvent.title,
369	          content: sourceEvent.body,
370	          source: sourceEvent.provider,
371	          sourceType: sourceEvent.eventType,
372	          sourceId: sourceEvent.sourceId,
373	          sourceReferences: sourceEvent.relations,
