383	      }
384	
385	      log.info("observation stored", {
386	        observationId: obs.id,
387	        externalId: obs.externalId,
388	        observationType,
389	        ingestLogId,
390	      });
391	
392	      return obs;
393	    });
394	
395	    // Step 6: Upsert entities and create junction rows
396	    const entityUpsertResult = await step.run(
397	      "upsert-entities-and-junctions",
398	      async () => {
399	        if (extractedEntities.length === 0) {
400	          return { count: 0, primaryEntityExternalId: null as string | null };
401	        }
402	
403	        // Upsert each entity and get back its ID + externalId for junction inserts.
404	        // externalId is needed to emit entity.upserted with the stable Pinecone vector key.
405	        const entityResults = await Promise.all(
406	          extractedEntities.map((entity) =>
407	            db
